//#region src/features/collections/services/collections.service.js
var getCollectionsApi = async () => {
	return (await axiosInstance.get("/collections")).data.data;
};
var getCollectionByIdApi = async (id) => {
	return (await axiosInstance.get(`/collections/${id}`)).data.data;
};
var createCollectionApi = async (data) => {
	return (await axiosInstance.post("/collections", data)).data.data;
};
var updateCollectionApi = async ({ id, ...data }) => {
	return (await axiosInstance.patch(`/collections/${id}`, data)).data.data;
};
var deleteCollectionApi = async (id) => {
	return (await axiosInstance.delete(`/collections/${id}`)).data.data;
};
var addSaveToCollectionApi = async ({ collectionId, saveId }) => {
	return (await axiosInstance.patch(`/collections/${collectionId}/saves/${saveId}`)).data.data;
};
var removeSaveFromCollectionApi = async ({ collectionId, saveId }) => {
	return (await axiosInstance.delete(`/collections/${collectionId}/saves/${saveId}`)).data.data;
};
//#endregion
//#region src/features/collections/hooks/useCollections.js
var useCollections = () => {
	return useQuery({
		queryKey: ["collections"],
		queryFn: getCollectionsApi
	});
};
var useCreateCollection = () => {
	const queryClient = useQueryClient();
	return useMutation({
		mutationFn: createCollectionApi,
		onSuccess: () => {
			queryClient.invalidateQueries({ queryKey: ["collections"] });
		}
	});
};
var useDeleteCollection = () => {
	const queryClient = useQueryClient();
	return useMutation({
		mutationFn: deleteCollectionApi,
		onSuccess: () => {
			queryClient.invalidateQueries({ queryKey: ["collections"] });
		}
	});
};
//#endregion
//#region src/features/tags/services/tags.service.js
var getTagsApi = async () => {
	return (await axiosInstance.get("/tags")).data.data;
};
var createTagApi = async (data) => {
	return (await axiosInstance.post("/tags", data)).data.data;
};
var updateTagApi = async ({ id, ...data }) => {
	return (await axiosInstance.patch(`/tags/${id}`, data)).data.data;
};
var deleteTagApi = async (id) => {
	return (await axiosInstance.delete(`/tags/${id}`)).data.data;
};
var addTagToSaveApi = async ({ tagId, saveId }) => {
	return (await axiosInstance.patch(`/tags/${tagId}/saves/${saveId}`)).data.data;
};
var removeTagFromSaveApi = async ({ tagId, saveId }) => {
	return (await axiosInstance.delete(`/tags/${tagId}/saves/${saveId}`)).data.data;
};
