var getSavesApi = async (params = {}) => {
	return (await axiosInstance.get("/saves", { params })).data.data;
};
var createSaveApi = async (data) => {
	return (await axiosInstance.post("/saves", data)).data.data;
};
var getSaveByIdApi = async (id) => {
	return (await axiosInstance.get(`/saves/${id}`)).data.data;
};
var updateSaveApi = async ({ id, ...data }) => {
	return (await axiosInstance.patch(`/saves/${id}`, data)).data.data;
};
var deleteSaveApi = async (id) => {
	return (await axiosInstance.delete(`/saves/${id}`)).data.data;
};
var getRelatedSavesApi = async (id) => {
	return (await axiosInstance.get(`/saves/${id}/related`)).data.data;
};
var getResurfaceSaveApi = async () => {
	return (await axiosInstance.get(`/saves/resurface`)).data.data;
};
